### XAML — Wrap CollectionView in RefreshView

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemsLayout>
                <LinearItemsLayout Orientation="Vertical"
                                   ItemSizingStrategy="MeasureFirstItem" />
            </CollectionView.ItemsLayout>
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}"
                                   FontSize="12" TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

### ViewModel

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _itemService;

    public ItemsViewModel(IItemService itemService)
    {
        _itemService = itemService;
    }

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? _selectedItem;

    [ObservableProperty]
    private bool _isRefreshing;

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _itemService.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false;   // must set false to hide spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (SelectedItem is null) return;

        await Shell.Current.GoToAsync($"details",
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null;        // clear so user can re-select same item
    }
}
```

### Key binding relationships

| XAML property | ViewModel property | Why |
|---|---|---|
| `IsRefreshing` | `IsRefreshing` (bool) | Two-way; set `false` when done to hide the spinner |
| `Command` (RefreshView) | `RefreshCommand` | Generated by `[RelayCommand]` on `RefreshAsync` |
| `ItemsSource` | `Items` (ObservableCollection) | Auto-updates UI on add/remove |
| `SelectedItem` | `SelectedItem` (TwoWay) | Tracks current selection; null it after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap → triggers navigation |

### Important notes

- **`ObservableCollection<T>`** — never use `List<T>`; it won't update the UI.
- **`IsRefreshing = false`** — must be set in `finally` or the spinner never stops.
- **Clear `SelectedItem`** after navigating so the same item can be tapped again.
- **`MeasureFirstItem`** — improves scroll performance for uniform row heights.
- **`x:DataType`** on both page and `DataTemplate` enables compiled bindings.
- **No `ViewCell`** — use `Grid`, `StackLayout`, or any `View` as the template root.
